        if voter_id not in self.votes:
            self.votes[voter_id] = {}
        if candidate not in self.votes[voter_id]:
            self.votes[voter_id][candidate] = 0
        self.votes[voter_id][candidate] += 1

    def get_votes(self):
        return self.votes

    def validate_votes(self):
        # Überprüfung, ob alle Eingaben gültig sind
        for voter_id, candidates in self.votes.items():
            if len(candidates) > 1:
                print(f"Warnung: Voter {voter_id} hat mehr als einen Kandidaten gewählt.")
            for candidate in candidates:
                if candidates[candidate] < 0:
                    print(f"Warnung: Voter {voter_id} hat für Kandidat {candidate} einen negativen Wert gewählt.")

    def check_manipulation(self):
        # Überprüfung auf Manipulationen
        for voter_id, candidates in self.votes.items():
            if len(candidates) == 1 and list(candidates.keys())[0] in ["Manipulation", "Fälschung"]:
                print(f"Warnung: Voter {voter_id} hat möglicherweise manipuliert.")

    def print_results(self):
        # Ausgabe der Ergebnisse
        for candidate, votes in self.votes.items():
            if isinstance(candidate, str):
                print(f"{candidate}: {sum(votes.values())}")
            else:
                print(f"Voter {candidate}: {self.votes[candidate]}")

